#include<bits/stdc++.h>
using namespace std;
long long a[30][50005],n,q,b[20][50005];
void init(){
	for(int i=1;i<=log2(n);i++){
		for(int j=1;j+(1<<i)<=n+1;j++){
			a[i][j]=max(a[i-1][j],a[i-1][j+(1<<(i-1))]);
            b[i][j]=min(b[i-1][j],b[i-1][j+(1<<(i-1))]);
            //cout<<a[i][j]<<" ";
		}
        //cout<<"\n";
	}
}
long long find(int l,int r){
	int k=log2(r-l+1);
	return max(a[k][l],a[k][r-(1<<k)+1])- min(b[k][l],b[k][r-(1<<k)+1]);
}
int main(){

	cin>>n>>q;
	for(int i=1;i<=n;i++){
		cin>>a[0][i];
        b[0][i]=a[0][i];
	}
   // cout<<"\n";
    init();
	for(int i=1;i<=q;i++){
		int x,y;
		cin>>x>>y;
		cout<<find(x,y)<<"\n";
	}
	return 0;
}
